{
    var settings = new XmlWriterSettings { Indent = true, Encoding = System.Text.Encoding.UTF8 };
    using (XmlWriter writer = XmlWriter.Create(xmlStream, settings))
    {
        writer.WriteStartDocument();
        writer.WriteStartElement("FormData");
        foreach (Field field in pdfDocument.Form.Fields)
        {
            writer.WriteStartElement("Field");
            writer.WriteAttributeString("Name", field.PartialName);
            writer.WriteAttributeString("Type", field.GetType().Name);
            writer.WriteString(GetFieldValue(field)); // custom helper that extracts the value per field type
