copy-document-info-after-pdf-comparison.code:
using (Document diffDoc = new Document(diffPath))
using (Document srcDoc = new Document(sourcePath))
{
    // copy standard metadata fields
    diffDoc.Info.Title       = srcDoc.Info.Title;
    diffDoc.Info.Author      = srcDoc.Info.Author;
    diffDoc.Info.Subject     = srcDoc.Info.Subject;
    diffDoc.Info.Keywords    = srcDoc.Info.Keywords;
    diffDoc.Info.Creator     = srcDoc.Info.Creator;
    diffDoc.Info.Producer    = srcDoc.Info.Producer;
    diffDoc.Info.CreationDate = srcDoc.Info.CreationDate;
    diffDoc.Info.ModDate      = srcDoc.Info.ModDate;
    diffDoc.Info.Trapped      = srcDoc.Info.Trapped;
    // copy any custom metadata entries
    foreach (var entry in srcDoc.Info)
        diffDoc.Info[entry.Key] = entry.Value;
    diffDoc.Save(diffPath);
}
